<?php $__env->startSection('content'); ?><div class="table-card"><table class="table align-middle"><tr><th>Product</th><th>Stock</th><th>Alert</th><th>Update</th></tr><?php $__currentLoopData = $products; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $product): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><tr><td><?php echo e($product->name); ?></td><td><?php echo e($product->stock_quantity); ?></td><td><?php if($product->stock_quantity <= $product->low_stock_limit): ?><span class="badge text-bg-danger">Low stock</span><?php else: ?><span class="badge text-bg-success">OK</span><?php endif; ?></td><td><form class="d-flex gap-2" method="post" action="<?php echo e(route('admin.inventory.update',$product)); ?>"><?php echo csrf_field(); ?><input class="form-control" style="max-width:120px" name="stock_quantity" value="<?php echo e($product->stock_quantity); ?>"><input class="form-control" name="note" placeholder="Note"><button class="btn btn-sm btn-primary">Update</button></form></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></table><?php echo e($products->links()); ?></div><?php $__env->stopSection(); ?>

